                  <button onClick={handleCreatePool} className="w-full py-4 bg-app-accent text-app-accent-text text-[10px] font-black uppercase tracking-widest hover:opacity-90">Create Reward Pool</button>
               </div>
            </div>

            <div className="lg:col-span-8 space-y-8">
               <h2 className="text-xs font-black uppercase tracking-[0.4em] border-b border-app-border pb-4">Active Pools</h2>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {state.giveawayPools.map(pool => (
                    <div key={pool.id} className="p-8 border border-app-border bg-app-bg space-y-6 relative overflow-hidden">
                       <div className="absolute top-0 right-0 p-4">
                          <span className={`text-[8px] px-2 py-0.5 font-black uppercase ${pool.isActive ? 'bg-green-500' : 'bg-red-500'} text-white`}>
                            {pool.isActive ? 'ACTIVE' : 'PAUSED'}
                          </span>
                       </div>
                       <div>
                          <p className="text-2xl font-black mono tracking-widest text-app-text">{pool.code}</p>
                          <p className="text-[10px] font-bold text-app-muted uppercase tracking-widest">Reward: ${pool.rewardPerUser} USDT</p>
                       </div>
                       <div className="space-y-4">
                          <div className="h-1 w-full bg-app-border">
                             <div className="h-full bg-app-accent" style={{ width: `${(pool.claimsCount / pool.maxClaims) * 100}%` }}></div>
                          </div>
                          <div className="flex justify-between items-baseline">
                             <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">Claims: {pool.claimsCount} / {pool.maxClaims}</p>
                             <p className="text-[10px] font-black uppercase tracking-widest text-app-text">${(pool.totalAmount - (pool.claimsCount * pool.rewardPerUser)).toFixed(2)} Left</p>
                          </div>
                       </div>
                       <div className="flex gap-2 pt-2">
                          <button onClick={() => updateGiveawayPoolStatus(pool.id, !pool.isActive)} className="flex-1 py-2 text-[8px] font-black uppercase border border-app-border hover:bg-app-accent hover:text-app-accent-text transition-all">Toggle</button>
                          <button onClick={() => confirm("Delete pool?") && deleteGiveawayPool(pool.id)} className="px-3 py-2 text-[8px] font-black text-red-500 border border-red-500/10 hover:bg-red-500 hover:text-white"><i className="fa-solid fa-trash"></i></button>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
          </div>
        </section>
      )}

      {activeTab === 'withdrawals' && (
        <section className="space-y-12">
          <div className="space-y-4 max-h-[800px] overflow-y-auto pr-4">
            {pendingWithdrawals.length === 0 ? (
              <div className="p-20 text-center opacity-20 border border-app-border border-dashed text-app-muted">No pending withdrawals.</div>
            ) : (
              pendingWithdrawals.map(tx => (
                <div key={tx.id} className="p-10 border border-app-border space-y-8 bg-app-surface">
                  <div className="flex justify-between items-start">
                    <div>
                      <p className="text-4xl font-black mono tracking-tighter mb-1 text-app-text">{tx.amount.toFixed(2)}</p>
                      <p className="text-[10px] font-bold text-app-muted uppercase tracking-widest">{tx.description}</p>
                    </div>
                    <span className="text-[10px] px-2 py-0.5 border border-app-border font-black uppercase tracking-widest text-app-text">Pending</span>
                  </div>
                  <div className="flex gap-px bg-app-border">
                    <button onClick={() => authorizeWithdrawalFirestore(tx.id, hotWallet)} className="flex-1 py-4 bg-app-accent text-app-accent-text text-[10px] font-black uppercase tracking-widest">Approve</button>
                    <button onClick={() => onManageWithdrawal(tx.id, TransactionStatus.REJECTED)} className="flex-1 py-4 bg-transparent border border-app-border text-app-text text-[10px] font-black uppercase tracking-widest">Reject</button>
                  </div>
                </div>
              ))
            )}
          </div>
        </section>
      )}
    </div>
  );
};

export default AdminPanel;

import { 
  doc, 
  getDoc, 
  setDoc, 
  updateDoc, 
  collection, 
  addDoc, 
  query, 
  where, 
  getDocs, 
  runTransaction,
  increment,
  limit,
  deleteDoc
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { db } from './firebase.ts';
import { AppState, User, Transaction, TransactionType, TransactionStatus, UserPackage, HotWalletConfig, Package, GiveawayPool } from './types.ts';
import { INITIAL_PACKAGES } from './constants.tsx';
import { generateUserWallet, checkUsdtDeposits, processUsdtWithdrawal, executeWalletSweep } from './tronService.ts';

// Dynamic Node Management
export const savePackageFirestore = async (pkg: Package) => {
  const pkgRef = doc(db, 'packages', pkg.id);
  await setDoc(pkgRef, { ...pkg, isActive: pkg.isActive ?? true }, { merge: true });
};

export const deletePackageFirestore = async (pkgId: string) => {
  await deleteDoc(doc(db, 'packages', pkgId));
};

// Giveaway System
export const createGiveawayPoolFirestore = async (pool: Omit<GiveawayPool, 'id' | 'claimsCount' | 'createdAt'>) => {
  const poolRef = doc(collection(db, 'giveawayPools'));
  const newPool: GiveawayPool = {
    ...pool,
    id: poolRef.id,
    claimsCount: 0,
    createdAt: Date.now()
  };
  await setDoc(poolRef, newPool);
  return newPool.id;
};

export const updateGiveawayPoolStatus = async (poolId: string, isActive: boolean) => {
  await updateDoc(doc(db, 'giveawayPools', poolId), { isActive });
};

export const deleteGiveawayPool = async (poolId: string) => {
  await deleteDoc(doc(db, 'giveawayPools', poolId));
};

export const processGiveawayClaimFirestore = async (userId: string, code: string) => {
  const q = query(collection(db, 'giveawayPools'), where('code', '==', code.trim().toUpperCase()), where('isActive', '==', true), limit(1));
  const snap = await getDocs(q);

  if (snap.empty) throw new Error("Invalid or inactive bonus code.");
  const pool = snap.docs[0].data() as GiveawayPool;

  if (pool.expiryDate && Date.now() > pool.expiryDate) throw new Error("This bonus code has expired.");
  if (pool.claimsCount >= pool.maxClaims) throw new Error("This reward pool has been fully claimed.");

  // Check Eligibility: At least one deposit
  if (pool.requireDeposit) {
    const txQ = query(collection(db, 'transactions'), where('userId', '==', userId), where('type', '==', TransactionType.DEPOSIT), limit(1));
    const txSnap = await getDocs(txQ);
    if (txSnap.empty) throw new Error("Eligibility Error: You must complete at least one USDT deposit to unlock bonus claims.");
  }

  const claimId = `${pool.id}_${userId}`;
  const claimRef = doc(db, 'giveawayClaims', claimId);
  const userRef = doc(db, 'users', userId);
  const poolRef = doc(db, 'giveawayPools', pool.id);

  await runTransaction(db, async (transaction) => {
    const claimSnap = await transaction.get(claimRef);
    if (claimSnap.exists()) throw new Error("You have already claimed this bonus.");

    const freshPoolSnap = await transaction.get(poolRef);
    const freshPool = freshPoolSnap.data() as GiveawayPool;
    if (freshPool.claimsCount >= freshPool.maxClaims) throw new Error("Rewards just ran out!");

    // Execute Claim
    transaction.set(claimRef, {
      id: claimId,
      poolId: pool.id,
      userId,
      amount: pool.rewardPerUser,
      timestamp: Date.now()
    });

    transaction.update(poolRef, {
      claimsCount: increment(1)
    });

    transaction.update(userRef, {
      profitBalance: increment(pool.rewardPerUser),
      totalEarned: increment(pool.rewardPerUser)
    });

    const txRef = doc(collection(db, 'transactions'));
    transaction.set(txRef, {
      id: txRef.id,
      userId,
      type: TransactionType.BONUS,
      amount: pool.rewardPerUser,
      status: TransactionStatus.COMPLETED,
      timestamp: Date.now(),
      description: `Giveaway Reward: ${pool.code}`
    });
  });
};

export const createFirestoreUser = async (userId: string, email: string, refCode: string | undefined): Promise<User> => {
  try {
    const cleanRefCode = refCode ? refCode.trim().toUpperCase() : '';
    const userRef = doc(db, 'users', userId);
    const existingSnap = await getDoc(userRef);

    if (existingSnap.exists()) {
      const data = existingSnap.data() as User;
      if (!data.referredBy && cleanRefCode) {
        await updateDoc(userRef, { referredBy: cleanRefCode });
        try {
          const refQuery = query(collection(db, 'users'), where('referralCode', '==', cleanRefCode), limit(1));
          const refSnap = await getDocs(refQuery);
          if (!refSnap.empty) {
            await updateDoc(doc(db, 'users', refSnap.docs[0].id), { referralCount: increment(1) });
          }
        } catch (e) {}
        return { ...data, referredBy: cleanRefCode };
      }
      return data;
    }

    const wallet = await generateUserWallet();
    let isFirstUser = false;
    const isDevAdmin = email.toLowerCase().includes('admin');

    try {
      const configRef = doc(db, 'system', 'status');
      const configSnap = await getDoc(configRef);
      if (!configSnap.exists()) {
        await setDoc(configRef, { initialized: true, rootAdmin: userId });
        isFirstUser = true;
      }
    } catch (e) {
      console.warn("System config read failed during signup, defaulting to standard user.");
    }

    const newUser: User = {
      id: userId,
      email,
      referralCode: (email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000)).replace(/[^A-Z0-9]/g, ''),
      referredBy: cleanRefCode,
      usdtDepositAddress: wallet.address.base58,
      depositPrivateKey: wallet.privateKey,
      capitalBalance: 0,
      profitBalance: 0,
      totalEarned: 0,
      isActive: true,
      isAdmin: isFirstUser || isDevAdmin, 
      referralCount: 0,
      referralEarnings: 0,
      welcomeBonus: 100 
    };

    await setDoc(userRef, newUser);

    if (cleanRefCode) {
      try {
        const refQuery = query(collection(db, 'users'), where('referralCode', '==', cleanRefCode), limit(1));
        const refSnap = await getDocs(refQuery);
        if (!refSnap.empty) {
          await updateDoc(doc(db, 'users', refSnap.docs[0].id), { referralCount: increment(1) });
        }
      } catch (refError) {}
    }

    return newUser;
  } catch (err: any) {
    throw new Error(err.message || "Profile Provisioning Error");
  }
};

export const fetchAllUsersFirestore = async (): Promise<User[]> => {
  const querySnapshot = await getDocs(collection(db, 'users'));
  return querySnapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as User));
};

export const toggleUserAdminFirestore = async (userId: string, currentStatus: boolean) => {
  const userRef = doc(db, 'users', userId);
  await updateDoc(userRef, { isAdmin: !currentStatus });
};

export const adminCreditUserFirestore = async (targetUserId: string, amount: number, type: 'capital' | 'profit') => {
  const userRef = doc(db, 'users', targetUserId);
  await runTransaction(db, async (transaction) => {
    const userSnap = await transaction.get(userRef);
    if (!userSnap.exists()) throw new Error("User not found");
    const update = type === 'capital' ? { capitalBalance: increment(amount) } : { profitBalance: increment(amount) };
    transaction.update(userRef, update);
    const txRef = doc(collection(db, 'transactions'));
    transaction.set(txRef, {
        id: txRef.id,
        userId: targetUserId,
        type: TransactionType.DEPOSIT,
        amount: amount,
        status: TransactionStatus.COMPLETED,
        timestamp: Date.now(),
        description: `Admin Credit: ${type === 'capital' ? 'Wallet' : 'Profit'} Balance`
    });
  });
};

export const syncUserDepositsFirestore = async (userId: string) => {
  const userRef = doc(db, 'users', userId);
  const userSnap = await getDoc(userRef);
  if (!userSnap.exists()) return;
  const user = userSnap.data() as User;
  const since = Date.now() - (24 * 60 * 60 * 1000);
  const deposits = await checkUsdtDeposits(user.usdtDepositAddress, since);

  for (const dep of deposits) {
    const q = query(collection(db, 'transactions'), where('txHash', '==', dep.hash));
    const existing = await getDocs(q);
    if (existing.empty) {
      await runTransaction(db, async (transaction) => {
        transaction.update(userRef, { capitalBalance: increment(dep.amount) });
        const txRef = doc(collection(db, 'transactions'));
        transaction.set(txRef, {
          id: txRef.id,
          userId,
          type: TransactionType.DEPOSIT,
          amount: dep.amount,
          status: TransactionStatus.COMPLETED,
          txHash: dep.hash,
          timestamp: dep.timestamp,
          description: `Confirmed TRC20 USDT Deposit.`
        });
      });
    }
  }
};

export const requestWithdrawalFirestore = async (userId: string, amount: number, address: string) => {
  const userRef = doc(db, 'users', userId);
  const userSnap = await getDoc(userRef);
  if (!userSnap.exists()) throw new Error("User profile not synced.");
  const userData = userSnap.data() as User;
  if (userData.profitBalance < amount) throw new Error("Insufficient profit balance.");
  const txRef = await addDoc(collection(db, 'transactions'), {
    userId,
    type: TransactionType.WITHDRAWAL,
    amount,
    status: TransactionStatus.PENDING,
    timestamp: Date.now(),
    description: `Withdrawal request to ${address}`
  });
  await updateDoc(userRef, { profitBalance: increment(-amount) });
  return txRef.id;
};

export const authorizeWithdrawalFirestore = async (txId: string, hotWallet: HotWalletConfig) => {
  const txRef = doc(db, 'transactions', txId);
  const txSnap = await getDoc(txRef);
  if (!txSnap.exists()) return;
  const txData = txSnap.data() as Transaction;
  const userRef = doc(db, 'users', txData.userId);
  const userSnap = await getDoc(userRef);
  const userData = userSnap.data() as User;
  const toAddress = userData.withdrawalAddress || txData.description.split(' ').pop() || '';

  try {
    const result = await processUsdtWithdrawal(hotWallet.privateKey, toAddress, txData.amount);
    await updateDoc(txRef, {
      status: TransactionStatus.COMPLETED,
      txHash: result.txHash,
      description: `TRC20 Withdrawal confirmed via Hot Wallet.`
    });
    return result.txHash;
  } catch (err: any) {
    const errorMsg = err?.message || 'Unknown blockchain error';
    await updateDoc(userRef, { profitBalance: increment(txData.amount) });
    await updateDoc(txRef, {
      status: TransactionStatus.REJECTED,
      description: `Blockchain Error: ${errorMsg}`
    });
    throw new Error(errorMsg);
  }
};

export const adminSweepUserFundsWithAmount = async (
  userId: string,
  userPrivateKey: string,
  userAddress: string,
  hotWalletAddress: string,
  hotWalletPrivateKey: string,
  amount: number
) => {
  try {
    const result = await executeWalletSweep(userPrivateKey, userAddress, hotWalletPrivateKey, hotWalletAddress, amount);
    await addDoc(collection(db, 'transactions'), {
      id: `sweep-${Date.now()}`,
      userId,
      type: TransactionType.SWEEP,
      amount: amount,
      status: TransactionStatus.COMPLETED,
      txHash: result.sweepTx,
      timestamp: Date.now(),
      description: `Admin Sweep to Hot Wallet`
    });
    return result.sweepTx;
  } catch (err: any) {
    throw new Error(err.message || "Sweep failed");
  }
};

export const updateUserProfileFirestore = async (userId: string, data: Partial<User>) => {
  await updateDoc(doc(db, 'users', userId), data);
};

export const updatePlatformSettingsFirestore = async (settings: Partial<AppState['platformSettings']>) => {
  await setDoc(doc(db, 'system', 'settings'), settings, { merge: true });
};

export const purchasePackageFirestore = async (userId: string, pkgId: string, currentPackages: Package[]) => {
  const pkg = currentPackages.find(p => p.id === pkgId);
  if (!pkg) throw new Error("Invalid Package Configuration");
  const activePkgsQuery = query(collection(db, 'activePackages'), where('userId', '==', userId), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const existingDocRef = activePkgsSnap.empty ? null : activePkgsSnap.docs[0].ref;
  const userRef = doc(db, 'users', userId);

  await runTransaction(db, async (transaction) => {
    const userSnap = await transaction.get(userRef);
    if (!userSnap.exists()) throw new Error("User does not exist!");
    const userData = userSnap.data() as User;
    let cost = pkg.minAmount;
    let isUpgrade = false;
    let currentData: UserPackage | null = null;
    if (existingDocRef) {
      const pkgSnap = await transaction.get(existingDocRef);
      if (pkgSnap.exists()) {
        currentData = pkgSnap.data() as UserPackage;
        if (currentData.packageId === pkgId) throw new Error("Plan already active.");
        if (pkg.minAmount <= currentData.amount) throw new Error("Downgrade not allowed.");
        cost = pkg.minAmount - currentData.amount;
        isUpgrade = true;
      }
    }
    if (userData.capitalBalance < cost) throw new Error(`Insufficient balance. Required: ${cost.toFixed(2)} USDT`);
    transaction.update(userRef, { capitalBalance: increment(-cost) });
    if (isUpgrade && existingDocRef && currentData) {
      transaction.update(existingDocRef, { packageId: pkg.id, amount: pkg.minAmount, activatedAt: Date.now(), lastPayoutAt: Date.now() });
    } else {
      const activePkgRef = doc(collection(db, 'activePackages'));
      transaction.set(activePkgRef, { id: activePkgRef.id, packageId: pkg.id, amount: pkg.minAmount, activatedAt: Date.now(), lastPayoutAt: Date.now(), isActive: true, totalEarned: 0, userId });
    }
    const txRef = doc(collection(db, 'transactions'));
    transaction.set(txRef, { id: txRef.id, userId, type: TransactionType.PURCHASE, amount: cost, status: TransactionStatus.COMPLETED, timestamp: Date.now(), description: isUpgrade ? `Upgrade to ${pkg.name}` : `Node Activation: ${pkg.name}` });
  });
};

export const processDailyRoiFirestore = async (settings: any, currentPackages: Package[]) => {
  if (!settings.isRoiEnabled || settings.platformPaused) return;
  const activePkgsQuery = query(collection(db, 'activePackages'), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const now = Date.now();
  const ONE_DAY_MS = 24 * 60 * 60 * 1000;
  for (const docSnap of activePkgsSnap.docs) {
    const ap = docSnap.data() as UserPackage;
    const pkg = currentPackages.find(p => p.id === ap.packageId);
    if (!pkg || pkg.isActive === false) continue;
    const lastPayout = ap.lastPayoutAt || ap.activatedAt;
    if (now - lastPayout < ONE_DAY_MS) continue;
    const dailyPercent = settings.roiOverride || pkg.dailyRoi;
    const earnings = ap.amount * (dailyPercent / 100);
    await runTransaction(db, async (transaction) => {
      const userRef = doc(db, 'users', ap.userId);
      transaction.update(userRef, { profitBalance: increment(earnings), totalEarned: increment(earnings) });
      transaction.update(doc(db, 'activePackages', docSnap.id), { totalEarned: increment(earnings), lastPayoutAt: now });
      const txRef = doc(collection(db, 'transactions'));
      transaction.set(txRef, { id: txRef.id, userId: ap.userId, type: TransactionType.ROI, amount: earnings, status: TransactionStatus.COMPLETED, timestamp: now, description: `Daily profit from ${pkg.name}` });
    });
  }
};

