          }}
          className="relative w-32 h-32 md:w-48 md:h-48 flex items-center justify-center"
        >
          {/* Outer Ring */}
          <div className="absolute inset-0 border-2 border-app-accent rounded-full border-dashed opacity-20"></div>
          {/* Inner Pulsing Hexagon */}
          <div className="w-24 h-24 md:w-36 md:h-36 border border-app-accent/50 rotate-45 flex items-center justify-center">
            <div className="w-full h-full border border-app-accent animate-pulse flex items-center justify-center">
                <div className="w-4 h-4 bg-app-accent shadow-[0_0_20px_var(--accent)]"></div>
            </div>
          </div>

          {/* Orbiting particles */}
          {[0, 120, 240].map((deg) => (
            <motion.div
              key={deg}
              animate={{ rotate: 360 }}
              transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
              className="absolute w-full h-full"
              style={{ transform: `rotate(${deg}deg)` }}
            >
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-1.5 h-1.5 bg-app-accent"></div>
            </motion.div>
          ))}
        </motion.div>

        <div className="mt-8 text-center">
          <p className="text-[10px] font-black uppercase tracking-[0.5em] text-app-accent animate-pulse">MINING ACTIVE</p>
          <p className="text-xs font-bold text-app-muted mt-2 mono">PROTOCOL: {activePkg.name.toUpperCase()}</p>
        </div>
      </div>

      {/* Data HUD Column */}
      <div className="lg:w-80 flex flex-col justify-between gap-8 border-l border-app-border lg:pl-8">
        {/* Real-time Metrics */}
        <div className="space-y-4">
          <div className="flex justify-between items-baseline group">
            <span className="text-[8px] font-black uppercase tracking-widest text-app-muted">Node Entropy</span>
            <span className="text-xs font-bold mono text-app-text">{(metrics.entropy * 100).toFixed(3)}%</span>
          </div>
          <div className="flex justify-between items-baseline group">
            <span className="text-[8px] font-black uppercase tracking-widest text-app-muted">Network Latency</span>
            <span className="text-xs font-bold mono text-app-text">{metrics.latency}ms</span>
          </div>
          <div className="flex justify-between items-baseline group">
            <span className="text-[8px] font-black uppercase tracking-widest text-app-muted">Quantum Hashrate</span>
            <span className="text-xs font-bold mono text-app-accent">{metrics.hashrate} GH/s</span>
          </div>
        </div>

        {/* Live Logs */}
        <div className="flex-1 bg-black/40 border border-app-border p-4 font-mono text-[8px] text-app-muted overflow-hidden">
          <div className="flex flex-col gap-1">
            <AnimatePresence initial={false}>
              {logs.map((log, i) => (
                <motion.div
                  key={log + i}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  className="whitespace-nowrap flex gap-2"
                >
                  <span className="text-app-accent/40">[{new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' })}]</span>
