            <motion.h1 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="text-6xl lg:text-8xl font-black uppercase tracking-tighter leading-none text-app-text"
            >
            Node Status: <br />
            <span className={pkgDetails ? "text-app-accent" : "text-app-muted/50"}>
                {pkgDetails ? 'Operational' : 'Standby'}
            </span>
            </motion.h1>
            <motion.p 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.2 }}
                className="serif italic text-xl text-app-muted max-w-xl"
            >
            {pkgDetails 
                ? `Running ${pkgDetails.name} protocol. High-yield liquidity provision is active.` 
                : "No active liquidity node detected. Deploy a node to commence yield generation."}
            </motion.p>
        </div>

        {/* Dynamic Mining Simulator / Active Node HUD */}
