                </div>
                <div className="p-8 border border-app-border bg-app-surface/40 flex flex-col justify-between h-40">
                  <span className="text-[10px] font-black uppercase tracking-[0.4em] text-app-muted">Next Cycle</span>
                  <p className="text-3xl font-black mono text-app-text">{timeLeft || 'CALCULATING'}</p>
                </div>
                <div className="p-8 border border-app-border bg-app-accent text-app-accent-text flex flex-col justify-between h-40">
                  <span className="text-[10px] font-black uppercase tracking-[0.4em] opacity-60">Node Health</span>
                  <div className="flex items-center gap-3">
                    <div className="w-4 h-4 rounded-full bg-app-accent-text animate-ping"></div>
                    <p className="text-3xl font-black mono uppercase">OPTIMAL</p>
                  </div>
                </div>
              </div>
            </motion.div>
        ) : (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="p-16 border border-app-border border-dashed text-center space-y-8 bg-app-surface/10"
