            whileHover={{ y: -5, backgroundColor: 'var(--bg-primary)', zIndex: 10 }}
            className={`bg-app-bg p-6 md:p-8 group relative transition-all duration-300 ${stat.highlight ? 'bg-app-surface' : ''}`}
