                        <button 
                            onClick={() => setPaymentConfig({
                                isEnabled: true,
                                provider: 'NOWPAYMENTS',
                                apiKey: '1NT6XEX-ZY4MXNK-P7CD1MV-TSD49VA',
                                publicKey: '7e167d15-8dda-488a-b131-d923abae1fea',
                                ipnSecret: 'KuFgtsis1DgqCbnBynz9xVI8/MVafiIt'
                            })}
                            className="px-6 py-4 border border-app-border text-app-muted hover:text-app-text text-[10px] font-black uppercase tracking-widest"
                            title="Fill Default Credentials"
                        >
