Here are the complete Firestore Security Rules. You can copy and paste this into your Firebase Console > Firestore Database > Rules tab.

```
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // --- Helper Functions ---

    // Check if the user is authenticated
    function isAuthenticated() {
      return request.auth != null;
    }

    // Check if the user matches the requested document ID
    function isOwner(userId) {
      return isAuthenticated() && request.auth.uid == userId;
    }

    // Check if the user is an admin
    // Note: We check the 'isAdmin' field on the user document. 
    // Secure apps should also use Custom Claims, but this works for this architecture.
    function isAdmin() {
      return isAuthenticated() && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.isAdmin == true;
    }

    // --- Collection Rules ---

    // USERS: Users can read/write their own data. Admins can read/write all.
    match /users/{userId} {
      allow read: if isOwner(userId) || isAdmin();
      allow create: if isOwner(userId); // Account creation
      allow update: if isOwner(userId) || isAdmin(); // Profile updates
      allow delete: if isAdmin();
    }

    // TRANSACTIONS: Users read own txs. Creation allowed for withdrawals (simulated).
    match /transactions/{txId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAdmin(); // Only admins can approve/reject/delete
    }

    // PACKAGES (Nodes): Public read. Admin write.
    match /packages/{packageId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // ACTIVE PACKAGES: Users read own. Admin read all. Server/Admin creates/updates.
    // For this client-side demo, we allow creation if owner matches.
    match /activePackages/{pkgId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow write: if isAuthenticated() && (request.resource.data.userId == request.auth.uid || isAdmin());
    }

    // GIVEAWAY POOLS: Public read (or auth only). Admin write.
    match /giveawayPools/{poolId} {
      allow read: if true; 
      allow write: if isAdmin();
    }

    // GIVEAWAY CLAIMS: Prevent double claiming via rules or code.
    // Here we allow read if owner or admin. Write if owner (simulated claim).
    match /giveawayClaims/{claimId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAdmin();
    }

    // SYSTEM / SETTINGS: Read public/auth. Write Admin.
    match /system/{docId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // VAULT / HOTWALLET: Admin only.
    match /vault/{docId} {
      allow read, write: if isAdmin();
    }
  }
}

