**Complete Firestore Security Rules**

Copy and paste the entire block below into the "Rules" tab of your Firebase Firestore Console.

These rules allow users to:
1.  Sign up and create their own user document.
2.  Update their own balance/profile (client-side logic simulation).
3.  Update *other* users' `referralCount` only when using a referral code.
4.  Update `giveawayPools` claim counts when claiming a reward.
5.  Create transactions for deposits and withdrawals.

Admins have full write access to everything.

```
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // --- Helper Functions ---

    function isAuthenticated() {
      return request.auth != null;
    }

    function isOwner(userId) {
      return isAuthenticated() && request.auth.uid == userId;
    }

    function isAdmin() {
      return isAuthenticated() && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.isAdmin == true;
    }

    // Check if the update is only modifying specific allowed keys
    function onlyUpdatingKeys(allowedKeys) {
      return request.resource.data.diff(resource.data).affectedKeys().hasOnly(allowedKeys);
    }

    // --- Collection Rules ---

    // USERS
    // 1. Owner can read/write own data (required for client-side balance updates/profile changes).
    // 2. Authenticated users can update another user's 'referralCount' (when using a referral code).
    // 3. Admin can do anything.
    match /users/{userId} {
      allow read: if isOwner(userId) || isAdmin();
      allow create: if isOwner(userId);
      allow update: if isOwner(userId) || isAdmin() || 
                    (isAuthenticated() && onlyUpdatingKeys(['referralCount', 'referralEarnings']));
      allow delete: if isAdmin();
    }

    // TRANSACTIONS
    // Users can create (deposit/withdraw/claim) and read their own.
    match /transactions/{txId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAdmin();
    }

    // PACKAGES (Nodes)
    // Publicly readable. Admin only write.
    match /packages/{packageId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // ACTIVE PACKAGES (User's purchased nodes)
    // Users create when buying. Users read own.
    match /activePackages/{pkgId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update: if isAdmin() || (isAuthenticated() && resource.data.userId == request.auth.uid);
    }

    // GIVEAWAY POOLS
    // 1. Public read (to see available pools).
    // 2. Authenticated users can update 'claimsCount' when claiming.
    // 3. Admin create/delete.
    match /giveawayPools/{poolId} {
      allow read: if true; 
      allow create, delete: if isAdmin();
      allow update: if isAdmin() || (isAuthenticated() && onlyUpdatingKeys(['claimsCount']));
    }

    // GIVEAWAY CLAIMS
    // Users read/create their own claim record.
    match /giveawayClaims/{claimId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAdmin();
    }

    // SYSTEM / SETTINGS
    // Public read (to check ROI status/pauses). Admin write.
    match /system/{docId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // VAULT / HOTWALLET
    // Admin only. Highly sensitive.
    match /vault/{docId} {
      allow read, write: if isAdmin();
    }
  }
}

