    >
      Log Out
    </button>
  </div>
);

// Helper to sanitize Firestore data (convert Timestamps/Refs to plain values)
const sanitizeDoc = (docSnap: any) => {
    const data = docSnap.data();
    const clean: any = { id: docSnap.id };

    if (!data) return clean;

    Object.keys(data).forEach(key => {
        const val = data[key];
        if (val && typeof val === 'object') {
            if (val.seconds !== undefined && val.nanoseconds !== undefined) {
                // Convert Timestamp to millis
                clean[key] = val.toMillis();
            } else if (val.path !== undefined) {
                // Convert Reference to path string
                clean[key] = val.path;
            } else {
                // Shallow copy other objects to break references
                clean[key] = { ...val };
            }
        } else {
            clean[key] = val;
        }
    });
    return clean;
};

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [dynamicPackages, setDynamicPackages] = useState<Package[]>([]);
  const [giveawayPools, setGiveawayPools] = useState<GiveawayPool[]>([]);
  const [myReferrals, setMyReferrals] = useState<User[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });
  const [paymentSettings, setPaymentSettings] = useState<PaymentSettings>({
    isEnabled: false,
    provider: 'NOWPAYMENTS',
    apiKey: '',
    publicKey: '',
    ipnSecret: ''
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register' | 'forgot-password'>('login');
  const [authError, setAuthError] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  const [showLanding, setShowLanding] = useState(true);
  const [showGuide, setShowGuide] = useState(false);
  const isInitialized = useRef(false);

  const [bonusCode, setBonusCode] = useState('');
  const [isClaimingBonus, setIsClaimingBonus] = useState(false);

  const [purchaseModal, setPurchaseModal] = useState<{
    pkgId: string;
    name: string;
    cost: number;
    action: string;
    type: 'PURCHASE' | 'INSUFFICIENT';
  } | null>(null);
  const [isProcessingPurchase, setIsProcessingPurchase] = useState(false);

  useEffect(() => {
    const unsub = onSnapshot(doc(db, 'system', 'settings'), 
      (doc) => { if (doc.exists()) setPlatformSettings(prev => ({ ...prev, ...doc.data() })); },
      (err) => console.warn("Settings listener restricted:", err.message)
    );

    const unsubPayments = onSnapshot(doc(db, 'system', 'payments'), 
      (doc) => { if (doc.exists()) setPaymentSettings(doc.data() as PaymentSettings); },
      (err) => console.warn("Payment settings listener restricted:", err.message)
    );

    const unsubPkgs = onSnapshot(collection(db, 'packages'), 
      (snap) => {
        const pkgs = snap.docs.map(d => ({ ...d.data(), id: d.id } as Package));
        pkgs.sort((a,b) => a.minAmount - b.minAmount);
        setDynamicPackages(pkgs.length > 0 ? pkgs : INITIAL_PACKAGES);
      },
      (err) => console.warn("Package listener restricted:", err.message)
    );

    // FIX: Removed orderBy('createdAt', 'desc') to prevent missing index error. Sorting client-side instead.
    const unsubPools = onSnapshot(collection(db, 'giveawayPools'), 
      (snap) => { 
        const pools = snap.docs.map(d => sanitizeDoc(d) as GiveawayPool);
        pools.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
        setGiveawayPools(pools); 
      },
      (err) => console.warn("Pool listener restricted (likely permissions):", err.message)
    );

    return () => { unsub(); unsubPayments(); unsubPkgs(); unsubPools(); };
  }, []);

  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;
    let unsubRefs: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();

      if (firebaseUser) {
        setIsLoading(true);
        setShowLanding(false);

        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = sanitizeDoc(docSnap) as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);

            if (!isInitialized.current) {
              if (view === 'auth') setView('dashboard');
              setShowGuide(true);
              isInitialized.current = true;
            }

            if (userData.referralCode) {
              const qRefs = query(collection(db, 'users'), where('referredBy', '==', userData.referralCode));
              unsubRefs = onSnapshot(qRefs, 
                (snap) => { 
                    const refs = snap.docs.map(d => sanitizeDoc(d) as User);
                    setMyReferrals(refs); 
                },
                (err) => console.warn("Referral list listener restricted")
              );
            }
          } else {
            setIsProvisioning(true);
            setIsLoading(false);
          }
        }, (err) => {
          console.error("Profile listen error:", err.message);
          setAuthError("Session synchronization error: " + err.message);
          setIsLoading(false);
        });

        unsubTx = onSnapshot(
          query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), 
          (snap) => {
            const txs = snap.docs.map(d => sanitizeDoc(d) as Transaction);
            setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
          },
          (err) => console.warn("Tx listener restricted")
        );

        unsubPk = onSnapshot(
          query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), 
          (snap) => {
            const pkgs = snap.docs.map(d => sanitizeDoc(d) as UserPackage);
            setActivePackages(pkgs);
          },
          (err) => console.warn("Active Pkg listener restricted")
        );

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setMyReferrals([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
        setShowLanding(true);
        isInitialized.current = false;
        setShowGuide(false);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      setAuthError(error?.message || "Login failed");
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      setAuthError(error?.message || 'Registration failed');
      setIsLoading(false);
      setIsProvisioning(false);
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handlePasswordReset = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) {
      setAuthError("Please enter your email.");
      return;
    }
    setIsLoading(true);
    try {
      await sendPasswordResetEmail(auth, email);
      alert("Password reset link sent!");
      setAuthMode('login');
    } catch (error: any) {
      setAuthError(error?.message || "Reset failed");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
      setShowLanding(true);
    } catch (err: any) {
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Min withdrawal is $${platformSettings.minWithdrawal}`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal requested.');
    } catch (err: any) {
      alert(err?.message || 'Withdrawal failed');
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Sync complete.');
    } catch (err: any) {
      alert('Sync Failed: ' + (err?.message || 'Error'));
    }
  };

  const handleBonusClaim = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !bonusCode.trim()) return;
    setIsClaimingBonus(true);
    try {
      await processGiveawayClaimFirestore(currentUser.id, bonusCode);
      alert("Bonus successfully credited to your Profit Balance!");
      setBonusCode('');
    } catch (err: any) {
      alert(err.message || "Failed to claim bonus.");
    } finally {
      setIsClaimingBonus(false);
    }
  };

  const handlePurchaseRequest = (pkgId: string) => {
    if (!currentUser) return;
    const pkg = dynamicPackages.find(p => p.id === pkgId);
    if (!pkg) return;

    const currentActive = activePackages.find(p => p.isActive);
    let cost = pkg.minAmount;
    let action = "Deploy Node";

    if (currentActive) {
        if (currentActive.packageId === pkgId) return;
        if (currentActive.amount >= pkg.minAmount) {
            alert("No downgrades allowed.");
            return;
        }
        cost = pkg.minAmount - currentActive.amount;
        action = "Upgrade Node";
    }

    if (currentUser.capitalBalance < cost) {
      setPurchaseModal({ pkgId, name: pkg.name, cost, action: 'Insufficient Funds', type: 'INSUFFICIENT' });
    } else {
      setPurchaseModal({ pkgId, name: pkg.name, cost, action, type: 'PURCHASE' });
    }
  };

  const confirmPurchase = async () => {
    if (!purchaseModal || !currentUser) return;
    if (purchaseModal.type === 'INSUFFICIENT') {
      setView('wallet');
      setPurchaseModal(null);
      return;
    }
    setIsProcessingPurchase(true);
    try {
      await purchasePackageFirestore(currentUser.id, purchaseModal.pkgId, dynamicPackages);
      alert(`${purchaseModal.action} successful!`);
      setPurchaseModal(null);
    } catch (err: any) {
      alert(`Error: ${err.message}`);
    } finally {
      setIsProcessingPurchase(false);
    }
  };

