export const purchasePackageFirestore = async (userId: string, pkgId: string, currentPackages: Package[]) => {
  const pkg = currentPackages.find(p => p.id === pkgId);
  if (!pkg) throw new Error("Invalid Package Configuration");
  const activePkgsQuery = query(collection(db, 'activePackages'), where('userId', '==', userId), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const existingDocRef = activePkgsSnap.empty ? null : activePkgsSnap.docs[0].ref;
  const userRef = doc(db, 'users', userId);

  await runTransaction(db, async (transaction) => {
    const userSnap = await transaction.get(userRef);
    if (!userSnap.exists()) throw new Error("User does not exist!");
    const userData = userSnap.data() as User;
    let cost = pkg.minAmount;
    let isUpgrade = false;
    let currentData: UserPackage | null = null;
    if (existingDocRef) {
      const pkgSnap = await transaction.get(existingDocRef);
      if (pkgSnap.exists()) {
        currentData = pkgSnap.data() as UserPackage;
        if (currentData.packageId === pkgId) throw new Error("Plan already active.");
        if (pkg.minAmount <= currentData.amount) throw new Error("Downgrade not allowed.");
        cost = pkg.minAmount - currentData.amount;
        isUpgrade = true;
      }
    }
    if (userData.capitalBalance < cost) throw new Error(`Insufficient balance. Required: ${cost.toFixed(2)} USDT`);
    transaction.update(userRef, { capitalBalance: increment(-cost) });
    if (isUpgrade && existingDocRef && currentData) {
      transaction.update(existingDocRef, { packageId: pkg.id, amount: pkg.minAmount, activatedAt: Date.now(), lastPayoutAt: Date.now() });
    } else {
      const activePkgRef = doc(collection(db, 'activePackages'));
      transaction.set(activePkgRef, { id: activePkgRef.id, packageId: pkg.id, amount: pkg.minAmount, activatedAt: Date.now(), lastPayoutAt: Date.now(), isActive: true, totalEarned: 0, userId });
    }
    const txRef = doc(collection(db, 'transactions'));
    transaction.set(txRef, { id: txRef.id, userId, type: TransactionType.PURCHASE, amount: cost, status: TransactionStatus.COMPLETED, timestamp: Date.now(), description: isUpgrade ? `Upgrade to ${pkg.name}` : `Node Activation: ${pkg.name}` });
  });
