### ⚠️ IMPORTANT: Update Firestore Rules ⚠️

Copy and paste the rules below into your **Firestore Console > Rules** tab.
These rules allow the app to check if a claim exists (which involves reading a potentially null resource). Without this, the bonus claim transaction will fail.

```
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    function isAuthenticated() { return request.auth != null; }
    function isOwner(userId) { return isAuthenticated() && request.auth.uid == userId; }
    function isAdmin() { return isAuthenticated() && get(/databases/$(database)/documents/users/$(request.auth.uid)).data.isAdmin == true; }
    function onlyUpdatingKeys(allowedKeys) { return request.resource.data.diff(resource.data).affectedKeys().hasOnly(allowedKeys); }

    match /users/{userId} {
      allow read: if isOwner(userId) || isAdmin();
      allow create: if isOwner(userId);
      allow update: if isOwner(userId) || isAdmin() || (isAuthenticated() && onlyUpdatingKeys(['referralCount', 'referralEarnings']));
      allow delete: if isAdmin();
    }

    match /transactions/{txId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAdmin();
    }

    match /packages/{packageId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    match /activePackages/{pkgId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update: if isAdmin() || (isAuthenticated() && resource.data.userId == request.auth.uid);
    }

    match /giveawayPools/{poolId} {
      allow read: if true; 
      allow create, delete: if isAdmin();
      allow update: if isAdmin() || (isAuthenticated() && onlyUpdatingKeys(['claimsCount']));
    }

    match /giveawayClaims/{claimId} {
      // FIX: Allow read if resource is null (check existence) or belongs to user
      allow read: if isAuthenticated() && (resource == null || resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAdmin();
    }

    match /system/{docId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    match /vault/{docId} {
      allow read, write: if isAdmin();
    }
  }
}

