### 2. Final & Complete Firestore Security Rules

Copy this block exactly into your Firebase Console. It covers every edge case, allows the necessary client-side updates (bonuses, purchases), and fixes the `runTransaction` null-check issue.

```
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // --- Helper Functions ---

    function isAuthenticated() { return request.auth != null; }

    function isOwner(userId) { return isAuthenticated() && request.auth.uid == userId; }

    function isAdmin() { 
      return isAuthenticated() && 
             get(/databases/$(database)/documents/users/$(request.auth.uid)).data.isAdmin == true; 
    }

    function onlyUpdatingKeys(allowedKeys) {
      return request.resource.data.diff(resource.data).affectedKeys().hasOnly(allowedKeys);
    }

    // --- Collection Rules ---

    // USERS
    // 1. Owner can read their own profile.
    // 2. Owner can update specific fields to support client-side logic (Purchases, Claims, Profile Edits).
    // 3. Authenticated users can update 'referralCount' on *other* users (Referral System).
    // 4. Admins have full access.
    match /users/{userId} {
      allow read: if isOwner(userId) || isAdmin();
      allow create: if isOwner(userId);

      allow update: if isAdmin() 
                    || (isOwner(userId) && onlyUpdatingKeys(['withdrawalAddress', 'capitalBalance', 'profitBalance', 'totalEarned', 'referralCode', 'referredBy']))
                    || (isAuthenticated() && onlyUpdatingKeys(['referralCount', 'referralEarnings']));

      allow delete: if isAdmin();
    }

    // TRANSACTIONS
    // 1. Users can read their own transactions.
    // 2. Users can create transactions (Deposit/Withdrawal requests).
    // 3. Admin can read/update/delete all.
    match /transactions/{txId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAdmin();
    }

    // PACKAGES (Product Catalog)
    // Public read, Admin write.
    match /packages/{packageId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // ACTIVE PACKAGES (Purchased Nodes)
    // 1. Users can read/create their own.
    // 2. Users can update their own (for upgrades).
    // 3. Admin can manage all.
    match /activePackages/{pkgId} {
      allow read: if isAuthenticated() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update: if isAdmin() || (isAuthenticated() && resource.data.userId == request.auth.uid);
    }

    // GIVEAWAY POOLS
    // Public read (to see active bonuses). Admin write.
    // Authenticated users update 'claimsCount' during claim process.
    match /giveawayPools/{poolId} {
      allow read: if true; 
      allow create, delete: if isAdmin();
      allow update: if isAdmin() || (isAuthenticated() && onlyUpdatingKeys(['claimsCount']));
    }

    // GIVEAWAY CLAIMS
    // 1. READ: Essential fix (resource == null) allows checking if claim exists before creating it.
    // 2. CREATE: Users create their own claim record.
    match /giveawayClaims/{claimId} {
      allow read: if isAuthenticated() && (resource == null || resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;
      allow update, delete: if isAdmin();
    }

    // SYSTEM SETTINGS
    // Public read (for Maintenance Mode / ROI status). Admin write.
    match /system/{docId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // SECURE VAULT
    // Admin Only.
    match /vault/{docId} {
      allow read, write: if isAdmin();
    }
  }
}

