                       <label className="text-[10px] font-black uppercase text-app-muted">Name</label>
                       <input value={editingNode.name} onChange={e => setEditingNode({...editingNode, name: e.target.value})} className="w-full bg-app-surface border-b border-app-border py-2 text-sm text-app-text outline-none focus:border-app-accent" />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase text-app-muted">Daily ROI %</label>
                       <input type="number" value={editingNode.dailyRoi} onChange={e => setEditingNode({...editingNode, dailyRoi: Number(e.target.value)})} className="w-full bg-app-surface border-b border-app-border py-2 text-sm text-app-text outline-none focus:border-app-accent" />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase text-app-muted">Min Amount</label>
                       <input type="number" value={editingNode.minAmount} onChange={e => setEditingNode({...editingNode, minAmount: Number(e.target.value)})} className="w-full bg-app-surface border-b border-app-border py-2 text-sm text-app-text outline-none focus:border-app-accent" />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase text-app-muted">Max Amount</label>
                       <input type="number" value={editingNode.maxAmount} onChange={e => setEditingNode({...editingNode, maxAmount: Number(e.target.value)})} className="w-full bg-app-surface border-b border-app-border py-2 text-sm text-app-text outline-none focus:border-app-accent" />
                    </div>
                    <div className="col-span-2 space-y-2">
                       <label className="text-[10px] font-black uppercase text-app-muted">Description</label>
                       <input value={editingNode.description} onChange={e => setEditingNode({...editingNode, description: e.target.value})} className="w-full bg-app-surface border-b border-app-border py-2 text-sm text-app-text outline-none focus:border-app-accent" />
                    </div>
                 </div>
                 <div className="flex gap-4">
                    <button onClick={() => setEditingNode(null)} className="flex-1 py-4 border border-app-border text-[10px] font-black uppercase">Cancel</button>
                    <button onClick={handleSaveNode} className="flex-1 py-4 bg-app-accent text-app-accent-text text-[10px] font-black uppercase">Save Configuration</button>
                 </div>
              </div>
            </div>
          )}
        </section>
      )}

      {/* CREDIT MODAL FIX */}
      {creditModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-[100] p-6">
          <div className="bg-app-bg border border-app-border p-8 w-full max-w-md space-y-8 shadow-2xl animate-in fade-in zoom-in duration-300">
             <div className="space-y-2">
               <h3 className="text-xl font-black uppercase tracking-tighter text-app-text">Manual Credit</h3>
               <p className="text-xs font-bold text-app-muted">Adjusting balance for <span className="text-app-text">{creditModal.user.email}</span></p>
             </div>

             <div className="space-y-6">
                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase tracking-widest text-app-muted">Amount (USDT)</label>
                   <input 
                    type="number" 
                    autoFocus
                    value={creditModal.amount} 
                    onChange={(e) => setCreditModal({...creditModal, amount: e.target.value})} 
                    className="w-full bg-app-surface border-b border-app-border py-3 text-lg font-mono text-app-text outline-none focus:border-app-accent" 
                    placeholder="0.00"
                   />
                </div>

                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase tracking-widest text-app-muted">Destination Balance</label>
                   <div className="grid grid-cols-2 gap-px bg-app-border">
                      <button 
                        onClick={() => setCreditModal({...creditModal, type: 'capital'})}
                        className={`py-3 text-[10px] font-black uppercase tracking-widest transition-colors ${creditModal.type === 'capital' ? 'bg-app-accent text-app-accent-text' : 'bg-app-bg text-app-muted hover:text-app-text'}`}
                      >
                        Capital
                      </button>
                      <button 
                        onClick={() => setCreditModal({...creditModal, type: 'profit'})}
                        className={`py-3 text-[10px] font-black uppercase tracking-widest transition-colors ${creditModal.type === 'profit' ? 'bg-app-accent text-app-accent-text' : 'bg-app-bg text-app-muted hover:text-app-text'}`}
                      >
                        Profit
                      </button>
                   </div>
                </div>
             </div>

             <div className="flex gap-4 pt-4 border-t border-app-border">
                <button 
                    onClick={() => setCreditModal(null)} 
                    disabled={isCrediting}
                    className="flex-1 py-3 border border-app-border text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text"
                >
                    Cancel
                </button>
                <button 
                  type="button"
                  disabled={isCrediting}
                  onClick={async (e) => {
                    e.preventDefault();
                    console.log("Starting credit...");
                    const amt = Number(creditModal.amount);
                    if (!creditModal.amount || isNaN(amt) || amt <= 0) {
                        alert("Please enter a valid amount greater than 0.");
                        return;
                    }
                    setIsCrediting(true);
                    try {
                        await adminCreditUserFirestore(creditModal.user.id, amt, creditModal.type);
                        setCreditModal(null);
                        alert(`Successfully credited $${creditModal.amount} to ${creditModal.type} balance.`);
                    } catch (err: any) {
                        console.error("Credit error:", err);
                        alert(`Error: ${err.message}`);
                    } finally {
                        setIsCrediting(false);
                    }
                  }} 
                  className="flex-1 py-3 bg-app-accent text-app-accent-text text-[10px] font-black uppercase tracking-widest hover:opacity-90 disabled:opacity-50"
                >
                  {isCrediting ? 'Processing...' : 'Confirm Credit'}
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

